    def queryResults(self, limit, queries):
        ball_color = {}
        color_count = {}
        result = []
        for x, y in queries:
            old = ball_color.get(x)
            if old is not None:
                color_count[old] -= 1
                if color_count[old] == 0:
                    del color_count[old]
            ball_color[x] = y
            color_count[y] = color_count.get(y, 0) + 1
            result.append(len(color_count))
        return result

