var queryResults = function(limit, queries) {
    const ballColor = new Map();
    const colorCount = new Map();
    const result = [];
    for (const [x, y] of queries) {
        const old = ballColor.get(x);
        if (old !== undefined) {
            const cnt = colorCount.get(old) - 1;
            if (cnt === 0) colorCount.delete(old);
            else colorCount.set(old, cnt);
        }
        ballColor.set(x, y);
        colorCount.set(y, (colorCount.get(y) || 0) + 1);
        result.push(colorCount.size);
    }
    return result;
};
